class PaymentProcessor(
    private val gateway: PaymentGateway,
    private val walletStore: WalletStore,
    private val protector: SensitiveDataProtector,
    private val dispatcher: CoroutineDispatcher = Dispatchers.IO
) {

    suspend fun process(request: PaymentRequest): PaymentResult = withContext(dispatcher) {
        val sanitizedRequest = sanitize(request)

        when (sanitizedRequest.type) {
            PaymentType.IN_APP_PURCHASE -> {
                val auth = gateway.authorize(sanitizedRequest)
                if (auth.status != PaymentStatus.AUTHORIZED) return@withContext auth
                gateway.capture(sanitizedRequest.id)
            }

            PaymentType.WALLET_TOP_UP -> {
                val auth = gateway.authorize(sanitizedRequest)
                if (auth.status != PaymentStatus.AUTHORIZED) return@withContext auth
                val creditOk = walletStore.credit(sanitizedRequest.userId, sanitizedRequest.amount)
                if (!creditOk) {
                    return@withContext PaymentResult(
                        requestId = sanitizedRequest.id,
                        status = PaymentStatus.FAILED,
                        message = "Wallet credit failed"
                    )
                }
                gateway.capture(sanitizedRequest.id)
            }

            PaymentType.WALLET_TRANSFER -> {
                val balance = walletStore.getBalance(sanitizedRequest.userId, sanitizedRequest.amount.currency)
                if (balance.amount < sanitizedRequest.amount.amount) {
                    return@withContext PaymentResult(
                        requestId = sanitizedRequest.id,
                        status = PaymentStatus.FAILED,
                        message = "Insufficient balance"
                    )
                }
                val debitOk = walletStore.debit(sanitizedRequest.userId, sanitizedRequest.amount)
                if (!debitOk) {
                    return@withContext PaymentResult(
                        requestId = sanitizedRequest.id,
                        status = PaymentStatus.FAILED,
                        message = "Wallet debit failed"
                    )
                }
                PaymentResult(
                    requestId = sanitizedRequest.id,
                    status = PaymentStatus.CAPTURED,
                    transactionId = UUID.randomUUID().toString(),
                    message = "Wallet transfer completed"
                )
            }
        }
    }

    fun encryptSensitive(value: String): EncryptedPayload = protector.encrypt(value.toByteArray(Charsets.UTF_8))

    fun decryptSensitive(payload: EncryptedPayload): String = String(protector.decrypt(payload), Charsets.UTF_8)

    private fun sanitize(request: PaymentRequest): PaymentRequest {
        require(request.amount.amount > BigDecimal.ZERO)
        require(request.amount.currency.length in 3..8)
        require(request.userId.isNotBlank())
        return request.copy(
            metadata = request.metadata.mapValues { (_, v) -> v.trim().take(256) }
        )
    }
}

class InMemoryWalletStore : WalletStore {
    private val balances = mutableMapOf<String, MutableMap<String, BigDecimal>>()

    override suspend fun getBalance(userId: String, currency: String): Money {
        val balance = balances[userId]?.get(currency) ?: BigDecimal.ZERO
        return Money(balance, currency)
    }

    override suspend fun debit(userId: String, amount: Money): Boolean {
        val userBalances = balances.getOrPut(userId) { mutableMapOf() }
        val current = userBalances[amount.currency] ?: BigDecimal.ZERO
        if (current < amount.amount) return false
        userBalances[amount.currency] = current.subtract(amount.amount)
        return true
    }

    override suspend fun credit(userId: String, amount: Money): Boolean {
        val userBalances = balances.getOrPut(userId) { mutableMapOf() }
        val current = userBalances[amount.currency] ?: BigDecimal.ZERO
        userBalances[amount.currency] = current.add(amount.amount)
        return true
    }
}

